SELECT t, groupArray((OSName, c)) AS groupArr FROM ( SELECT (intDiv(toUInt32(event_time), 30) * 30) * 1000 AS t, OSName, sum(req_count) c FROM requests
INNER JOIN oses USING (OS) WHERE event_date >= toDate(1735787045) AND event_date <= toDate(1735790706) AND event_time >= toDateTime(1735787045) AND event_time <= toDateTime(1735790706) GROUP BY t, OSName ORDER BY t, OSName) GROUP BY t ORDER BY t